import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import { Building2, Upload, Image as ImageIcon } from "lucide-react";

const SchoolProfilePage = () => {
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState(false);
  const [logoPreview, setLogoPreview] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    address: "",
    phone: "",
    email: "",
    school_type: "",
    logo_url: "",
    motto: "",
    vision: "",
    mission: "",
    principal_name: "",
    website: "",
    established_year: ""
  });

  const [user] = useState(() => authService.getUser() || {});

useEffect(() => {
  fetchSchoolProfile();
}, []);

const fetchSchoolProfile = async () => {
  try {
    const currentUser = authService.getUser();

    if (!currentUser?.school_id) return;

    const res = await apiClient.get(`/schools/${currentUser.school_id}`);

    if (res?.data) {
      setFormData(res.data);

      if (res.data.logo_url) {
        setLogoPreview(res.data.logo_url);
      }
    }
  } catch (e) {
    console.error("PROFILE LOAD ERROR:", e?.response?.data || e?.message);
    toast.error("Failed to load profile");
  } finally {
    setLoading(false);
  }
};
  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      setLogoPreview(reader.result);
      setFormData({ ...formData, logo_url: reader.result });
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async (e) => {
  e.preventDefault();

  try {
    const payload = {
      ...formData,
      email: formData.email || user?.email || "admin@test.com",
      admin_name: user?.full_name || "Admin",
      admin_email: user?.email || formData.email || "admin@test.com",
      admin_password: "12345678",
      admin_phone: user?.phone || formData.phone || ""
    };

    // 🔥 CREATE SCHOOL
    if (!user?.school_id) {
      const res = await apiClient.post("/register-school", payload);

      toast.success("School created successfully");

      const onboarding = res?.data?.onboarding;

      if (onboarding?.step === 2) {
        window.location.href = `/onboarding/complete-profile?school=${res.data.school_id}`;
        return;
      }

      if (res?.data?.school_slug) {
        window.location.href = `/s/${res.data.school_slug}`;
        return;
      }

      return;
    }

    // 🔥 UPDATE SCHOOL (THIS IS WHERE YOUR PATCH BELONGS)
    const clean = Object.fromEntries(
      Object.entries(formData || {}).filter(([_, v]) => v !== "")
    );

    await apiClient.patch(`/schools/${user.school_id}`, clean);

    toast.success("Profile updated");
    setEditing(false);
    fetchSchoolProfile();

  } catch (e) {
    console.error("FULL ERROR:", e?.response?.data || e?.message);

    let errorMessage = "Operation failed";

    const detail = e?.response?.data?.detail;

    if (detail) {
      if (typeof detail === "string") {
        errorMessage = detail;
      } else if (Array.isArray(detail)) {
        errorMessage = detail
          .map(err => err?.msg || JSON.stringify(err))
          .join(", ");
      } else {
        errorMessage = JSON.stringify(detail);
      }
    } else if (e?.response?.data?.message) {
      errorMessage = e.response.data.message;
    } else if (e?.message) {
      errorMessage = e.message;
    }

    toast.error(errorMessage);
  }
};

